210: 	if err := fileutil.TouchDirAll(cfg.Logger, cfg.SnapDir()); err != nil {
211: 		cfg.Logger.Fatal(
212: 			"failed to create snapshot directory",
213: 			zap.String("path", cfg.SnapDir()),
214: 			zap.Error(err),
215: 		)
216: 	}
217: 
218: 	if err := fileutil.RemoveMatchFile(cfg.Logger, cfg.SnapDir(), func(fileName string) bool {
219: 		return strings.HasPrefix(fileName, "tmp")
220: 	}); err != nil {
221: 		cfg.Logger.Error(
