700: func (wal *bootstrappedWAL) MemoryStorage() *raft.MemoryStorage {
701: 	s := raft.NewMemoryStorage()
702: 	if wal.snapshot != nil {
703: 		s.ApplySnapshot(*wal.snapshot)
704: 	}
705: 	if wal.st != nil {
706: 		s.SetHardState(*wal.st)
707: 	}
708: 	if len(wal.ents) != 0 {
709: 		s.Append(wal.ents)
710: 	}
711: 	return s
712: }
713: 
714: func (wal *bootstrappedWAL) CommitedEntries() []raftpb.Entry {
715: 	for i, ent := range wal.ents {
716: 		if ent.Index > wal.st.Commit {
717: 			wal.lg.Info(
718: 				"discarding uncommitted WAL entries",
719: 				zap.Uint64("entry-index", ent.Index),
720: 				zap.Uint64("commit-index-from-wal", wal.st.Commit),
721: 				zap.Int("number-of-discarded-entries", len(wal.ents)-i),
722: 			)
723: 			return wal.ents[:i]
724: 		}
725: 	}
726: 	return wal.ents
727: }
728: 
729: func (wal *bootstrappedWAL) NewConfigChangeEntries() []raftpb.Entry {
730: 	return serverstorage.CreateConfigChangeEnts(
731: 		wal.lg,
732: 		serverstorage.GetEffectiveNodeIDsFromWALEntries(wal.lg, wal.snapshot, wal.ents),
733: 		uint64(wal.meta.nodeID),
734: 		wal.st.Term,
735: 		wal.st.Commit,
736: 	)
737: }
738: 
739: func (wal *bootstrappedWAL) AppendAndCommitEntries(ents []raftpb.Entry) {
740: 	wal.ents = append(wal.ents, ents...)
741: 	err := wal.w.Save(raftpb.HardState{}, ents)
742: 	if err != nil {
743: 		wal.lg.Fatal("failed to save hard state and entries", zap.Error(err))
744: 	}
745: 	if len(wal.ents) != 0 {
746: 		wal.st.Commit = wal.ents[len(wal.ents)-1].Index
747: 	}
748: }
